const Q_PHYSICS_2016=[{"id": "objective>Physics>2016>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a current of 2.5A flows through an electrolyte for 3 hours and 1.8g of a substance is deposited, what is the mass of the substance that would be deposited if a current of 4A flows through it for 4.8 hours?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.4g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.6g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.8g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.2g</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  <br/> Current, I = 2.5A → Initial <br/> Time, t = 3hours → Initial = 3 x 3600 = 10800seconds <br/> Mass (Initial), M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 1.8g <br/> Current, I = 4A → Final <br/> Times, t = 4.8hours → Final = (4.8x3600)seconds <br/> Mass (final), M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ? <br/> Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2.5 x 10,800 <br/> Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 27000C ...... <br/> Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>= I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=4</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">4.8</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">3600</td></tr></table></div> <br/> Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 69120C <br/>  <br/> From Faraday's Law of Electrolysis <br/> → m ∝ Q <br/> M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 1.8/27000 = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/69120 <br/> 1/15000 = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/69120 <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 69120/15000 = 4.608g  <br/>  = 4.6g</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2016>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a common emitter configuration, the output voltage is through the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">base</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emitter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">resistor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">collector</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In common emitter configuration, input voltage (VBE) is applied between base and emitter terminals, output voltage VCE is applied between emitter and collector while Emitter is connected to both input and output. Base is the input terminal, collector is the output terminal and emitter is the common terminal for both input and output.</div>", "topic": "INTRODUCTORY ELECTRONICS : TRANSISTORS"}, {"id": "objective>Physics>2016>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above that show the positions of a cone. The position which can be described as neutral equilibrium is represented as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Z only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y and X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y and Z</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Z only is in neutral equilibrium because after a slight displacement it will remain in its new position.</div>", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY"}, {"id": "objective>Physics>2016>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A force of 500N is applied to a steel wire of cross-sectional area of 0.2m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>, the tensile stress is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Force, F = 500N <br/> Cross-sectional Area, A = 0.2m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> Tensile stress = ? <br/> Recall that: Tensile stress = Force/Area <br/> = 500/0.2 = 2500Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> = 2.5x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> </div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>2016>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sensitivity of a galvanometer is increased by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing the number of turns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the voltage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing the number of turns</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sensitivity of a galvanometer is directly proportional to the number of turns in the coil. Therefore, increasing the number of turns in the coil will increase the sensitivity of the galvanometer.</div>", "topic": "MAGNETIC FIELD : MOVING COIL AND MOVING IRON INSTRUMENTS"}, {"id": "objective>Physics>2016>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">PHCN measures its electrical energy in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kWh</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wh</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">-PHCN measures its electric energy in kwh. <br/> - Electrical energy is measured in kwh from E = P x t <br/> Where 'E' is the electric energy, P, the power (in kw) and t, time in (hour). <br/> </div>", "topic": "ELECTRICAL ENERGY AND POWER : COMMERCIAL UNIT OF ELECTRIC ENERGY AND POWER"}, {"id": "objective>Physics>2016>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the force acting on an electron of charge 1.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C placed in an electric field of intensity 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Vm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-13</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-14</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-12</span>N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The charge, Q = 1.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span>C <br/> Electric field intensity, I = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Vm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Recall that: Force = charge x intensity <br/> Force = 1.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-19</span> x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> <br/> Force = 1.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-14</span>.</div>", "topic": "ELECTROSTATICS : COULOMB’S INVERSE SQUARE LAW ELECTRIC FIELD AND POTENTIAL"}, {"id": "objective>Physics>2016>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The bond between silicon and germanium is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ionic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrovalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dative</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bond between silicon and germanium is covalent. Both silicon and germanium are semiconductors and belong to the same group in the periodic table. They share electrons to form a covalent bond. An ionic bond is formed when one atom donates an electron to another atom. An electrovalent bond is another term for an ionic bond. A dative bond is a type of covalent bond where both electrons come from the same atom.</div>", "topic": "INTRODUCTORY ELECTRONICS"}, {"id": "objective>Physics>2016>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> From the diagram above, the point that represents the elastic limit is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">R</div>", "<div style=\"font-family:Cambria;font-size:17px;\">T</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">S</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- 'R' is the elastic limit <br/> - Elastic limit is the point beyond which force is not directly proportional to extension. Within the elastic limit, force is directly proportional to extension, i.e hooke's law is usually obeyed.</div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>2016>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The correct expression for the potential at a point, distance r from a charge q, in an electric field is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">q<hr size=\"1\" />4πε<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">q<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4πε<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>r</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">q<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4πε<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">q<hr size=\"1\" />4πε<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>r</td></tr></table></div></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Potential</td><td style=\"text-align:center;\">at</td><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">point</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">all</td><td style=\"text-align:center;\">an</td><td style=\"text-align:center;\">electric</td><td style=\"text-align:center;\">field</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Forcexdistance<hr size=\"1\" />Charge</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">Electric</td><td style=\"text-align:center;\">potential,</td><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">W<hr size=\"1\" />q</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">W</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">r</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">q<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4π<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Ʃ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></span>r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">r</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">q<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4π<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Ʃ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></span>r</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">q<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4π<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Ʃ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></span>r</td><td style=\"text-align:center;\">&#247; </td><td style=\"text-align:center;\">q</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">q<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4π<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Ʃ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></span>r</td><td style=\"text-align:center;\">&#215;</td><td style=\"text-align:center;\">1<hr size=\"1\" />q</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">q<hr size=\"1\" />4πε<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>r</td></tr></table></div></div>", "topic": "ELECTROSTATICS : COULOMB’S INVERSE SQUARE LAW ELECTRIC FIELD AND POTENTIAL"}, {"id": "objective>Physics>2016>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A circuit has a resistance of 200Ω. The resistance of the circuit can be reduced to 120Ω when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an 80Ω resistor is connected to it in series</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a 240Ω resistor is connected to it in series</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a 300Ω resistor is connected to it in parallel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a 150Ω resistor is connected to it in parallel</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The resistance of the circuit can be reduced to 12Ω when a 300Ω resistor is connected in parallel. <br/> Check: <br/> 1/Re = 1/300 + 1/200 <br/> 1/Re = 200 + 300/(200)(300) <br/> 1/Re = 500/60000 <br/> Re = 120Ω <br/> </div>", "topic": "CURRENT ELECTRICITY : RESISTANCE IN SERIES AND IN PARALLEL"}, {"id": "objective>Physics>2016>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a property of steel? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It can be used for making temporary magnets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It cannot retain its magnetism longer than iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It can be used for making permanent magnets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It can easily be magnetized and demagnetized</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Steel, particularly certain types like alloy steel, can retain its magnetism for a long time, making it suitable for permanent magnets.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS"}, {"id": "objective>Physics>2016>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which parts of a d.c generator convert an a.c in the armature to a d.c in the external circuit?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Commutator and brushes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Field poles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Armature and core</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Slip rings and brushes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The commutator and bruches are components in a d.c generator that convert an a.c in the armature to a d.c in the external circuit.</div>", "topic": "ELECTROMAGNETIC INDUCTION : A.C. AND D.C GENERATORS"}, {"id": "objective>Physics>2016>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a container is filled with ice to the brim, what happens to the level of water when the ice completely melts?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The water in the glass outflows</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The level of water goes up</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The level of water remains unchanged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The level of water drops</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- When the ice is present in the container, it occupies a particular volume. It dissolves partially which implies that the container now contains some particles of ice and some amount of water. <br/> - When these ice particles completely melt, it will become water and this water it becomes will occupy the volume the ice form of the newly formed water occupied. Then no change will be observed in the level of water. <br/>  <br/> </div>", "topic": "CHANGE OF STATE~~CHANGE OF STATE : MELTING"}, {"id": "objective>Physics>2016>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a sonometer has a fundamental frequency of 450Hz, what is the frequency of the fifth overtone?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">456Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">444Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2700Hz</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Fundamental frequency, f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = 450Hz <br/> The frequency of the fifth overtone, f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> = ? <br/> Recall: f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span> = (n+1)f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>: f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> = 6f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = 6 x 450 = 2700Hz.</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : OVERTONES PRODUCED BY VIBRATING STRINGS AND THEIR COLUMNS"}, {"id": "objective>Physics>2016>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a red rose flower is observed in blue light, what colour does the observer see?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Magenta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Blue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yellow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Red</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a red rose is illuminated by blue light, the red pigment in the rose absorbs the blue light, but reflects the red light. However, because the blue light is also present, it mixes with the reflected red light, creating the perception of magenta.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS : COLOUR MIXING"}, {"id": "objective>Physics>2016>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which type of motion do the wheels of a moving car undergo?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rotational and oscillatory motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Translational and rotational motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vibratory and translational motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Random and translational motion</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The wheels of a moving car undergo both translational and rotational motion. Translational motion is when an object moves along a path in any of the three spatial dimensions. Rotational motion is when an object moves in a circular path around a central point. The wheels of a car move forward (translational motion) while also spinning (rotational motion).</div>", "topic": "MOTION: TYPES OF MOTION"}, {"id": "objective>Physics>2016>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a pump is capable of lifting 5000kg of water through a vertical height of 60m in 15min, the power of the pump is  <br/> [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>Js<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>Js<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Js<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Js<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The mass, m of water = 5000kg  <br/>  The height, h = 60m  <br/>  The time, t = 15min = 900 seconds  <br/>  g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> * Power = Energy/time <br/>  * The energy form in this case is the potential energy (P.E) <br/>  Recall: P.E = mgh <br/> ∴ Power = mgh/t = 5000 x 10 x 60/900 = 50 x 10 x 60/9 = 30000/9  <br/>  = 3.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>Js<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "WORK, ENERGY AND POWER: POWER"}, {"id": "objective>Physics>2016>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a charge of 2μC is situates in a field of intensity 400NC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, the force on the charge is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-9</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">8</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  The charge, Q = 2µC = 2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>C  <br/>  The Electric field intensity, I = 400Nc<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  <br/>  Force, F = ?  <br/>  Recall that F = IQ  <br/>  F = 2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> x 4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/>  F = 8 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>N</div>", "topic": "ELECTROSTATICS : COULOMB’S INVERSE SQUARE LAW ELECTRIC FIELD AND POTENTIAL"}, {"id": "objective>Physics>2016>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The capacitance of a parallel plate capacitor is 20μF in air and 60μF in the presence of a dielectric. What is the dielectric constant? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> - The capacitance of the parallel plate capacitor = 20µF (in air) = &#949;<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> <br/> - The capacitance in the presence of the dieletric = 60µF = &#949; <br/> - The dielectric constant, Ʃ = ? <br/>  Recall that: <br/> &#949;<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> x k = &#949; <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">k</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&#949;<hr size=\"1\" />&#949;<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60uf<hr size=\"1\" />20uf</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3</td></tr></table></div></div>", "topic": "CAPACITORS : CAPACITANCE OF A CAPACITORS"}, {"id": "objective>Physics>2016>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a metal wire 4m long and cross-sectional area 0.8mm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> has a resistance of 6Ωm, find the resistivity of the wire. <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>Ωm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>Ωm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>Ωm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>Ωm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The length, L of the wire = 4m <br/> The cross-sectional area, A = 0.8mm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>; A = 0.8x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> The resistance, R = 6Ω; Resistivity, P = ? <br/>  Recall that: R = PI/A <br/> P = RA/L: P = 6x0.8x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>/4  <br/>  = 1.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>Ωm</div>", "topic": "CURRENT ELECTRICITY: RESISTIVITY AND CONDUCTIVITY"}, {"id": "objective>Physics>2016>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A train with an initial velocity of 20ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> is subjected to a uniform deceleration of 2ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>. The time required to bring the train to a complete halt is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40s</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The initial velocity, u = 20ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> The deceleration = -2ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/>  <br/> The time, t at which the final velocity, v = 0 is unknown <br/>  <br/> * recall that: V = u + at <br/> O = 20 - 2t <br/>  -20 = -2t  <br/>  t = 10s</div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2016>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electric device is rated 2000W, 250V. Calculate the maximum current it can take.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">9A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8A</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  The power rating, P = 2000W <br/> The voltage, V = 250V <br/> The maximum current, I = ? <br/>  * Recall that: <br/> P = IV <br/> I = P/V = 2000/250  <br/> = 8A</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2016>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a brick is taken from the earth's surface to the moon, its mass <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">remains constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">becomes zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduces</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a brick is taken from the earth's surface to the moon, its mass remains constant. It is its weight that reduces because the acceleration due to gravity of the moon is 1/6 times that of the earth.</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2016>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Steam from boiling water cause more damage on skin than boiling water itself because <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">steam has latent heat of fusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">steam brings heat more easily by convection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water has a high specific heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the steam is at a higher temperature than the water</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Steam from boiling water causes more damage on the skin than the boiling water itself does because the steam is at a higher temperature than the water. steam bring heat more easily by convection</div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF VAPORIZATION"}, {"id": "objective>Physics>2016>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ground is always cold at night because the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">earth radiates heat to the atmosphere at night</div>", "<div style=\"font-family:Cambria;font-size:17px;\">atmosphere reflects the sun energy at night</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the atmosphere absorbs the sun energy at night</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sun no longer shines at night</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The earth radiates heat in the atmosphere, this results  in a owered temperature of the ground at night </div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2016>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A radioactive isotope has a decay constant of 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, calculate its average life. <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>s</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> - The decay constant, k = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/>  - The average life, t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1/2</span> = ? <br/>  Recall that: t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1/2</span> = 0.6930/k  <br/>  ∴ t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1/2</span> = 6.93 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> seconds</div>", "topic": "ELEMENTARY MODERN PHYSICS : HALF-LIFE AND DECAY CONSTANT"}, {"id": "objective>Physics>2016>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>x + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><em>x</em> → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Y + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>n + energy  <br/> What type of reaction is represented by the equation above?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fission</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  Then nuclear reaction: <br/>  <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>X + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>X → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Y + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>n + energy <br/>  This is a typical representation of nuclear fusion as smaller atoms are combined to form a larger one, and accompanied with the release of energy and a radiation.</div>", "topic": "ELEMENTARY MODERN PHYSICS : FUSION AND FISSION"}, {"id": "objective>Physics>2016>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following has no effect on radiation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nature of the surface</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surface area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Density does not directly affect radiation. Radiation is influenced by factors such as the nature of the surface, surface area, and temperature.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2016>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The particle nature of light is demonstrated by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">speed of light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffraction of light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">photoelectric effect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colours of light</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The particulate nature of matter was demonstrated by Sir Fresnel using two phenomena, which includes: <br/>  - Tyndal effect <br/>  - Photoelectric effect <br/>  * Tyndal effect is the scattering of light rays after which a colloidal solution is placed along the path of propagation of the rays of light <br/>  * Photoelectric effect is the emission of electrons from the surface of a metal after which monochromatic light rays have been incident on the surface of the metal.</div>", "topic": "ELEMENTARY MODERN PHYSICS : PHOTOELECTRIC EFFECTS"}, {"id": "objective>Physics>2016>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following could be effectively used to reduce friction?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kerosene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Grease</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Petrol</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Greese would be effectively used to reduce friction as it will increase the sliding/motion of the surfaces in contact due to its high viscosity.</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2016>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> From the diagram above, calculate the moment of a force about point O.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">100Nm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50Nm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">45Nm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150Nm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram <br/>  - The moment of the force about point O = 200 x X <br/>  - X = 0.5cos60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> = 0.25m <br/>  ∴ The moment of the force about O = 200 x 0.25 = <span style=\"text-decoration:underline;\">50Nm</span></div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2016>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>I. Electrical potential <br/> II. Torque <br/> III. Kinetic energy <br/> IV. Momentum</strong> <br/> Which of the quantities listed above are vectors?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  <br/> Four physical quantities <br/>  <br/> - Electric potential - Kinetic energy <br/> - Torque - Momentum <br/> * All potentials are scale quantities <br/> * All forms of energy are scaler quantities <br/>  * Torque and momentum are vector quantities</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2016>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The instrument used for accurate measurement of the internal and external diameters of a pipe is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">vernier callipers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">micrometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spherometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metre rule</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vernier callipers is best used for the accurate measurement of the internal and external diameter of a pipe.</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2016>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In alternating current circuit at resonance, the angle of lead or lag is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">π<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>/2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">π<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">π<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>/3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an alternating current circuit at resonance, the angle of lead or lag is (π/2). This is why cosθ = O at resonance. <br/>  <br/> At resonance, XL=Xc, the phase angle of the circuit is zero</div>", "topic": "SIMPLE A. C. CIRCUITS : RESONANCE AND RESONANCE FREQUENCY"}, {"id": "objective>Physics>2016>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a charge moves through an electric circuit in the direction of an electric force, it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gains potential energy and loses kinetic energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loses potential energy and gains kinetic energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loses both potential and kinetic energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gains both potential and kinetic energy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a charge moves through an electric circuit in the direction of an electric force, it loses potential energy and gains kinetic energy.</div>", "topic": "ELECTROSTATICS : COULOMB’S INVERSE SQUARE LAW ELECTRIC FIELD AND POTENTIAL"}, {"id": "objective>Physics>2016>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An image in a convex lens is upright and magnified 3 times. If the focal length of the lens is 15cm, what is the object distance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16cm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The magnification, m = 3 <br/> The object distance, u = u <br/> The image distance, v = -3u (An erect image of a convex lens is usually virtual, i.e formed at the back of the lens, so v = -ve) <br/> The focal length, f = 15cm <br/> recall that: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />v</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />15</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-(</td><td style=\"text-align:center;\">1<hr size=\"1\" />3u</td><td style=\"text-align:center;\">)</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />u</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />15</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />3u</td></tr></table></div> <br/> 3u = 30 <br/>  <br/> u = 10cm</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2016>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a compound microscope, the objective and the eye piece focal lengths are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">short</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the same</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at infinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">long</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> In a compound microscope  the objective and age piece focal length are short <br/>  <br/> The objective and the eyepiece of a compound microscope must have short focal length so as to have larger angular magnification and magnifying power.</div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2016>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A man 1.5m tall is standing 3m in front of a pinhole camera whose distance between the hole and the screen is 0.1m.  What is the height of the image of the man on the screen?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.15m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.05m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.30m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The height, H of the man = 1.5m <br/> The distance, d between the man and the camera = 3m <br/> The distance, x between the hole and the screen of the camera = 0.1m <br/> The height, l of the image = ? <br/> recall: <br/> Image height/Object height = Image distance/Object distance <br/> I/1.5 = 0.1/3 <br/> 3l = 0.15 <br/> l = 0.15/3 = 0.05</div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2016>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>I. Change of state. <br/> II. Diffusion. <br/> III. Radiation <br/> IV. Osmosis</strong> <br/> Which of the processes above can be explained using the kinetic theory?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">All processes except radiation (III) can be explained using the kinetic theory of matter.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : KINETIC THEORY"}, {"id": "objective>Physics>2016>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>I. Density of the liquid. <br/> II. Depth below the surface of the liquid. <br/> III. Surface Area of the Liquid.</strong> <br/> In which of the statements above will pressure be dependent?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The density of the liquid and the debth, h below the surface of the liquid are pressure dependent <br/> from: Pressure, P = dgh <br/> Where d,g and h are density, acceleration due to gravity and the depth below the surface of the liquid</div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2016>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A piece of cork floats in a liquid. What fraction of its volume will be immersed  in the liquid? [density of the cork  = 0.25 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>, density of the liquid = 1.25 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> - A piece of cork which floats in a liquid <br/> - The density of the cork, dc = 0.25 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>KGM<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> - The density of the liquid, dl = 1.25 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>KGM<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/>  If a solid floats in a liquid, then the upthrust in the liquid is equal to the weight of the solid in air. <br/> ∴ U = W <br/> V x a/x x d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> x g = V x d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> x g ...... (1) <br/> - Where (a/x) is the fraction of the solid submerged <br/> - V is the volume of the solid <br/>  Equation (1) becomes  <br/>  a/x x d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = ds <br/>  a/x x 1.25x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.25x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  A/X = 0.25 X 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>/1.25X10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 25/125 = 1/5  <br/>  = 0.2</div>", "topic": "LIQUIDS AT REST : LAW OF FLOATATION"}, {"id": "objective>Physics>2016>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A block of aluminium is heated electrically by a 30W heater. If the temperature rises by 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C in 5 minutes, the heat capacity of the aluminium is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">100 JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">200 JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">900 JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">90 JK<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/>  <br/> Power, P = 30W <br/> Increase in temp., ∆θ = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C <br/> Time, t = 5minutes = 300seconds <br/> Heat capacity, H = ? <br/> Recall that: Energy = Power x times <br/>  <br/> ∴ E = 30 x 300 = 9000J <br/> heat capacity = E/∆θ = 9000J/10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C = 900Jk<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2016>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A copper rod is 10.0m at 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C. Find its new length when it is heated to 50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C. [Linear expansivity of copper = 1.7 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10.3m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.0m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15.1m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The original length of the rode = 10.0m = l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/>  The final length of the rod = ? = l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>  The initial temp. of the rod = 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C = θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/>  The final temp. of the rod = 50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C = θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>  The linear expansivity of copper, ∝<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> = 7 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/>  <br/> Recall that: <br/>  ∝ = l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>∆θ  <br/>  ∴ 1.7 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> = l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-10/10(20)  <br/>  1.7x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> x 10 x 20 = l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - 10  <br/>  340 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> = l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-10 <br/> 3.4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>+10 = l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/>  l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 10 + 0.0034  <br/>  l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 10.0034m <br/>  = 10.0m</div>", "topic": "HEAT TRANSFER: LINEAR EXPANSIVITY"}, {"id": "objective>Physics>2016>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The angle of deviation of light of various colours passing through a triangular prism increases in the order.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">green → violet → blue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blue → red → green</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blue → green → red</div>", "<div style=\"font-family:Cambria;font-size:17px;\">red → green → blue</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The angle of deviation of light of various colour passing a triangular prism increases in the order <br/> red → green → blue.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>2016>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a tube of small radius opened at both ends is placed in a liquid, the liquid will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">remain at the same level irrespective of whether the liquid wets the glass or not</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall below the liquid level if the liquid gets wet the glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rise above the liquid level if the liquid does not wet the glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall below the liquid level if the liquid does not wet the glass</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If a tube of small radius opened at both ends is placed in a liquid, the liquid will fall below the liquid level if the liquid does not wet flask <br/>  <br/> * This is a test for capillarity and also a test for force types (wether adhesive or cohesive).</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>2016>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which type of motion do the wheels of a moving car undergo? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rotational and oscillatory motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Vibratory and translational motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Random and translational motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Translational and rotational motion</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- The wheel of a moving car undergoes both translational and rotational motion <br/> - The circumference of the wheel undergoes rotational motion and the centre of the wheel undergoes translational motion.</div>", "topic": "MOTION: TYPES OF MOTION"}, {"id": "objective>Physics>2016>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A transverse wave and a longitudinal wave travelling in the same direction in a medium differ essentially in their</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">amplitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direction of vibration of the particles of the medium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">period of vibration of the particles of the medium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">frequency</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A transverse wave and a longitudinal wave travelling in the same direction in a medium differ essentially in the direction of vibration of particles of the medium.</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2016>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The coefficient of friction between two perfectly smooth surface is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">infinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">half</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Friction arises due to the irregularities on the surfaces of objects. If the surfaces are perfectly smooth, there are no irregularities and hence no friction.</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2016>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A car accelerates uniformly from rest at 3ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>, its velocity after travelling a distance of 24m is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">72ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">36ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">12 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">144 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Applying Newton's equation of motion; v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>= u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>+ 2as  <br/>  Since the car accelerates from rest, u = 0  <br/>  Hence, v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>= 2 x 3 x 24  <br/>  v = √ 6 x 6 x 4 = 6 x 2  <br/>  = 12m/s.</div>", "topic": "MOTION: LINEAR MOTION"}];
